var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"비상, 비상!! 집결하라!! 다크─세븐!!","JPN":"非常事態！　非常事態！！　集結せよ！！　ダーークセブン！！","ENG":"Danger! Danger!! Assemble!! DAARK SEVEN!!","TWN":"緊急，緊急！立即集合！Dark 7！"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"비상! 비상!! 일어나라!! 사이버─캣!!","JPN":"非常事態！　非常事態！！　起きろ！！　サイバーーキャット！！","ENG":"Danger! Danger!! Wake up, Cyber Caaat!!","TWN":"緊急情況！快起來！賽博——貓！"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"으으, 진짜!! <color=#ff3636>[검열됨]</color>!! <color=#ff3636>[검열됨]</color>!!","JPN":"うう、もう！！　<color=#ff3636>[検閲済]</color>！！　<color=#ff3636>[検閲済]</color>！！","ENG":"Ugh, c'mon!! <color=#ff3636>[BLEEP]</color>!! <color=#ff3636>[BLEEP]</color>!!","TWN":"呃呃，討厭！<color=#ff3636>[嗶——]</color>！！<color=#ff3636>[嗶——]</color>！！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"<color=#ff3636>[검열됨]</color>!! <color=#ff3636>[검열됨]</color>!! 니들은 잠도 없어!?","JPN":"<color=#ff3636>[検閲済]</color>！！　<color=#ff3636>[検閲済]</color>！！　アンタたちは寝ないっての！？","ENG":"<color=#ff3636>[BLEEP]</color>!! <color=#ff3636>[BLEEP]</color>!! Don't you guys even SLEEP?!!","TWN":"<color=#ff3636>[嗶——]</color>！！<color=#ff3636>[嗶——]</color>！！你們都不睡覺的嗎？！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"기껏 연차까지 쓰고 수면보충 좀 하려는데, 꼭두새벽부터 시끄럽게 무슨 짓이야, 대체!?","JPN":"人がせっかく有給休暇まで使って睡眠補充しようとしてるのに、朝っぱらからうるさいのよ、もう！！","ENG":"I even used my PTO to get some well-needed sleep, and you HAD to cause a ruckus this early in the morning?!","TWN":"我好不容易休假想補眠，你們大清早的到底在吵什麼？！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"어이, 어이, 진정하라구. 사이버 캣. 벌써 해가 중천이야.","JPN":"ちょっと、ちょっと、落ち着いてよ。サイバーキャット。もうお昼よ。","ENG":"Whoa, whoa. Calm down, Cyber Cat. It's already noon.","TWN":"喂喂，冷靜點，賽博貓，現在都已經中午咧。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"일찍 일어나는 해커가 정보를 낚는 법이라고.","JPN":"早起きするハッカーこそ情報キャッチできるものよ。","ENG":"The early hacker catches the info.","TWN":"俗話說早起的駭客才有情報可釣。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"앨버트 말이 옳아. 다크─세븐의 일원으로서 좀 더 자각을 가지는 게 어때, 사이버 캣?","JPN":"そのとおり。ダーークセブンの一員として、もっと自覚を持った方がいいんじゃないか？　サイバーキャット。","ENG":"Albert's right. Why don't you be a bit more diligent? After all, you're a member of Daark Seven!","TWN":"亞伯特說得對。身為Dark 7的一員，能不能有點自覺，賽博貓？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"……아하, 그러셔?","JPN":"……へえ、そうくるんだ？","ENG":"...Hah. Really?","TWN":"……哀，是嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"그래. 어디 얼마나 중대한 일로 호출하셨는지 들어볼까?","JPN":"いいわ。そんなに言うなら、どれだけ重大な仕事で呼び出したのか、聞いてみようじゃないの。","ENG":"OK. So what crucial matter is this about?","TWN":"好吧，那就讓我來聽聽，你們到底有什麼情報？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"반드시 중요한 일이어야만 할 거야.","JPN":"重大なことじゃなかったら、わかってるわよね？","ENG":"It better be something important.","TWN":"最好是有什麼重要的事。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"그렇지 않으면 착불로 궤도 미사일을 받아보게 될 테니까.","JPN":"着払いで軌道ミサイルを送りつけてやるから。","ENG":"Or else, you'll be getting a very special package called a ballistic missile.","TWN":"否則我會用貨到付款的方式，讓你們收到軌道導彈！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"후, 후후…… 기대하시라!","JPN":"ふ、ふふ……任せて！","ENG":"Ha, ha ha... Prepare yourself!","TWN":"呵呵……敬請期待吧！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"이 몸께서는 이번에 개최될 관리국 테크 컨퍼런스에 대한 미공개 홍보영상을 빼돌렸단 말씀!","JPN":"この私が、今度開催される管理局のテックカンファレンスについての未公開宣伝映像を盗み取ってきたのよ！","ENG":"Because I got leaks of the unreleased promotional video for the Administration Tech Conference that's happening soon!","TWN":"最近不是要舉辦管理局技術大會嗎？我把他們還沒公開的宣傳影片給弄來囉！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"테크 컨퍼런스? 매년 관리국 기술을 시연하는 박람회를 말하는 거지?","JPN":"テックカンファレンス？　毎年管理局の技術を披露する博覧会のことよね？","ENG":"Tech Conference? The annual expo where they showcase the Administration's technology?","TWN":"技術大會？你說的是每年展示管理局技術的博覽會吧？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"정식 라이센스가 없으면 입장할 수도 없는 행사잖아!?","JPN":"正式ライセンスがないと入場すらできないイベントじゃないか！？","ENG":"You can't even get in without an official license!","TWN":"你說那個沒有通行證根本進不去的博覽會嗎？！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"엣헴! 좀 더 찬양해도 좋다고, 제군들?","JPN":"えっへん！　もっと褒めてくれてもいいのよ、諸君？","ENG":"Ahem! Feel free to continue with the compliments.","TWN":"嘿嘿！快誇我！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};